      /* <flatten type="Javascript"> */
function load$GridVoucherDetail$(g) {
  g.add_itemValueChanged(onChange$GridVoucherDetail$);
  g.add_onResponseComplete(on$GridVoucherDetail$ResponseComplete);
  g.add_commandEvent(on$GridVoucherDetail$ExecuteCommand);
  g.$a = {
    gia_nt_sl: '[gia_nt]:=([gia_nt] == 0 ? ([so_luong] != 0 ? ([tien_nt]/[so_luong]) : 0) : [gia_nt])',
    gia_sl: '[gia]:=([gia] == 0 ? ([so_luong] != 0 ? ([tien]/[so_luong]) : 0) : [gia])',

    gia: '[gia]:=[gia_nt]*[$ty_gia]',

    tien_nt: '[tien_nt]:=[so_luong]*[gia_nt]',
    tien_tg: '[tien]:=[tien_nt]*[$ty_gia]',
    tien_sl: '[tien]:=[so_luong]*[gia]',

    nk_nt: '[nk_nt]:=[tien_nt]*[thue_suat_nk]/100',
    nk_tg: '[nk]:=[nk_nt]*[$ty_gia]',
    nk: '[nk]:=[tien]*[thue_suat_nk]/100',
    ttdb_nt: '[ttdb_nt]:=([tien_nt]+[nk_nt])*[thue_suat_ttdb]/100',
    ttdb_tg: '[ttdb]:=[ttdb_nt]*[$ty_gia]',
    ttdb: '[ttdb]:=([tien]+[nk])*[thue_suat_ttdb]/100',
    thue_nt: '[thue_nt]:=([tien_nt]+[nk_nt]+[ttdb_nt])*[thue_suat]/100',
    thue_tg: '[thue]:=[thue_nt]*[$ty_gia]',
    thue: '[thue]:=([tien]+[nk]+[ttdb])*[thue_suat]/100',

    t_so_luong: ['t_so_luong', 'so_luong'],
    t_tien_nt: ['t_tien_nt', 'tien_nt'],
    t_tien: ['t_tien', 'tien'],
    t_nk_nt: ['t_nk_nt', 'nk_nt'],
    t_nk: ['t_nk', 'nk'],
    t_ttdb_nt: ['t_ttdb_nt', 'ttdb_nt'],
    t_ttdb: ['t_ttdb', 'ttdb'],
    t_thue_nt: ['t_thue_nt', 'thue_nt'],
    t_thue: ['t_thue', 'thue'],

    t_tt_nt: '[t_tt_nt]:=[t_tien_nt]+[t_nk_nt]+[t_ttdb_nt]+[t_thue_nt]+[t_cp_nt]',
    t_tt: '[t_tt]:=[t_tien]+[t_nk]+[t_ttdb]+[t_thue]+[t_cp]'
  };
  g.$h = [['voucherCode', 'String', g._voucherCode], 'ma_dvcs'];
  udf$Detail$(g);
}
function dispose$GridVoucherDetail$(g) {
  g.$a = null;
  try {g.remove_commandEvent(on$GridVoucherDetail$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridVoucherDetail$ResponseComplete);} catch (ex) {}
  try {g.remove_itemValueChanged(onChange$GridVoucherDetail$);} catch (ex) {}
}
function onChange$GridVoucherDetail$Item(o) {o.grid.request(o, 'Item', 'Item', ['ma_vt'], o.grid.$h, true);}
function onChange$GridVoucherDetail$UOM(o) {o.grid.request(o, 'UOM', 'UOM', ['ma_vt', 'dvt', 'so_luong'], o.grid.$h, true);}
function onChange$GridVoucherDetail$ImportTaxCode(o) {o.grid.request(o, 'ImportTaxCode', 'ImportTaxCode', ['ma_thue_nk']);}
function onChange$GridVoucherDetail$ExciseTaxCode(o) {o.grid.request(o, 'ExciseTaxCode', 'ExciseTaxCode', ['ma_thue_ttdb']);}
function onChange$GridVoucherDetail$TaxCode(o) {o.grid.request(o, 'GetTaxRate', 'GetTaxRate', ['ma_thue']);}
function on$GridVoucherDetail$RowChange(g, f) {
  g.executeAggregate([g.$a.t_so_luong, g.$a.t_tien_nt, g.$a.t_tien, g.$a.t_nk_nt, g.$a.t_nk, g.$a.t_ttdb_nt, g.$a.t_ttdb, g.$a.t_thue_nt, g.$a.t_thue]);
  f.executeExpression([g.$a.t_tt_nt, g.$a.t_tt]);
}
function onChange$GridVoucherDetail$(sender, eventArgs) {
  var o = eventArgs.get_object(), g = o.grid, f = g.get_element().parentForm, name = o.field.Name;
  switch (name) {
    case 'so_luong':
      g.validExpression(o, [g.$a.tien_nt, g.$a.tien_tg, g.$a.nk_nt, g.$a.nk_tg, g.$a.ttdb_nt, g.$a.ttdb_tg, g.$a.thue_nt, g.$a.thue_tg],
        [g.$a.t_so_luong, g.$a.t_tien_nt, g.$a.t_tien, g.$a.t_nk_nt, g.$a.t_nk, g.$a.t_ttdb_nt, g.$a.t_ttdb, g.$a.t_thue_nt, g.$a.t_thue],
        [g.$a.t_tt_nt, g.$a.t_tt], 'gia_nt');
      break;
    case 'gia_nt':
      g.validExpression(o, [g.$a.gia, g.$a.tien_nt, g.$a.tien_tg, g.$a.nk_nt, g.$a.nk_tg, g.$a.ttdb_nt, g.$a.ttdb_tg, g.$a.thue_nt, g.$a.thue_tg],
        [g.$a.t_tien_nt, g.$a.t_tien, g.$a.t_nk_nt, g.$a.t_nk, g.$a.t_ttdb_nt, g.$a.t_ttdb, g.$a.t_thue_nt, g.$a.t_thue],
        [g.$a.t_tt_nt, g.$a.t_tt], 'tien_nt');
      break;
    case 'gia':
      g.validExpression(o, [g.$a.tien_sl, g.$a.nk, g.$a.ttdb, g.$a.thue], [g.$a.t_tien, g.$a.t_nk, g.$a.t_ttdb, g.$a.t_thue], [g.$a.t_tt], 'tien');
      break;
    case 'tien_nt':
      if (f._calPrice) g.validExpression(o, [g.$a.gia_nt_sl, g.$a.gia]);
      g.validExpression(o, [g.$a.tien_tg, g.$a.nk_nt, g.$a.nk_tg, g.$a.ttdb_nt, g.$a.ttdb_tg, g.$a.thue_nt, g.$a.thue_tg],
        [g.$a.t_tien_nt, g.$a.t_tien, g.$a.t_nk_nt, g.$a.t_nk, g.$a.t_ttdb_nt, g.$a.t_ttdb, g.$a.t_thue_nt, g.$a.t_thue],
        [g.$a.t_tt_nt, g.$a.t_tt]);
      break;
    case 'tien':
      if (f._calPrice) g.validExpression(o, [g.$a.gia_sl]);
      g.validExpression(o, [g.$a.nk, g.$a.ttdb, g.$a.thue], [g.$a.t_tien, g.$a.t_nk, g.$a.t_ttdb, g.$a.t_thue], [g.$a.t_tt], 'nk');
      break;
    case 'nk_nt':
      g.validExpression(o, [g.$a.nk_tg, g.$a.ttdb_nt, g.$a.ttdb_tg, g.$a.thue_nt, g.$a.thue_tg], [g.$a.t_nk_nt, g.$a.t_nk, g.$a.t_ttdb_nt, g.$a.t_ttdb, g.$a.t_thue_nt, g.$a.t_thue], [g.$a.t_tt_nt, g.$a.t_tt]);
      break;
    case 'nk':
      g.validExpression(o, [g.$a.ttdb, g.$a.thue], [g.$a.t_nk, g.$a.t_ttdb, g.$a.t_thue], [g.$a.t_tt], 'ttdb');
      break;
    case 'ttdb_nt':
      g.validExpression(o, [g.$a.ttdb_tg, g.$a.thue_nt, g.$a.thue_tg], [g.$a.t_ttdb_nt, g.$a.t_ttdb, g.$a.t_thue_nt, g.$a.t_thue], [g.$a.t_tt_nt, g.$a.t_tt]);
      break;
    case 'ttdb':
      g.validExpression(o, [g.$a.thue], [g.$a.t_ttdb, g.$a.t_thue], [g.$a.t_tt], 'thue');
      break;
    case 'thue_nt':
      g.validExpression(o, [g.$a.thue_tg], [g.$a.t_thue_nt, g.$a.t_thue], [g.$a.t_tt_nt, g.$a.t_tt]);
      break;
    case 'thue':
      g.validExpression(o, null, [g.$a.t_thue], [g.$a.t_tt]);
      break;
    default:
      break;
  }
}
/* </flatten> */
function on$GridVoucherDetail$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm;
  switch (action) {&ScriptCheckGridAction;
    case 'AfterRemoveRow':
      on$GridVoucherDetail$RowChange(g, f)
      break;
    case 'AfterCloneRow':
      g.setItemFieldValue('stt_rec0', e.type.Value, '');
      on$GridVoucherDetail$RowChange(g, f)
      break;
    case 'Check':
      if (!(g.validRowExpression('so_luong', '[so_luong] != 0'))) break;
      break;
    case 'Retrieve':
      if (f._action == 'View') break;
      switch (e.type.Value) {
        case '10':
          if (f.getItemValue('loai_ct') != '2' && f.validFields('ma_kh, ngay_lct')) g.showForm('PIBlanketFilter');
          break;
        case '30':
          if (f.validFields('ngay_lct')) g.showForm('PIRequisitionFilter');
          break;
        case '40':
          if (f.validFields('ma_kh, ngay_lct')) g.showForm('PIAllocatedFilter');
          break;
        default:
          break;
        }
      break;
    case 'Copying':
      set$Voucher$EmptyExternalField(g, 'sl_nhan, sl_hd, stt_rec_hd, stt_rec0hd, stt_rec_nc, stt_rec0nc, stt_rec_kh, stt_rec0kh');
      break;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function on$GridVoucherDetail$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object, f = g.get_element().parentForm;
  switch (context) {
    case 'Item':
      var v = (result[11].Value == '' ? 'false' : 'true'), t = (result[8].Value == '' ? 'false' : 'true');
      g.setItemGridBehavior(o, [
        ['dvt', result[2].Value, '', true],
        ['he_so', result[3].Value, null, null],
        ['ma_thue_nk', [result[8].Value, t], '', null],
        ['thue_suat_nk', [result[9].Value, t], null, null],
        ['ma_thue', [result[11].Value, v], '', null],
        ['thue_suat', [result[12].Value, v], null, null]
      ]);
      if (v == 'true' || t == 'true') g.validExpression(o, [g.$a.nk_nt, g.$a.nk_tg, g.$a.ttdb_nt, g.$a.ttdb_tg, g.$a.thue_nt, g.$a.thue_tg], [g.$a.t_nk_nt, g.$a.t_nk, g.$a.t_ttdb_nt, g.$a.t_ttdb, g.$a.t_thue_nt, g.$a.t_thue], [g.$a.t_tt_nt, g.$a.t_tt]);
      g.live(o, 'dvt');
      break;
    case 'UOM':
      g.setItemGridBehavior(o, [['he_so', result[0].Value, null, true]]);
      break;
    case 'ImportTaxCode':
      if (g._getItemValue(o.row, g._getColumnOrder('thue_suat_nk')) != result[0].value) {
        g.setItemGridBehavior(o, [['thue_suat_nk', result[0].Value, '', false]]);
        g.validExpression(o, [g.$a.nk_nt, g.$a.nk_tg, g.$a.ttdb_nt, g.$a.ttdb_tg, g.$a.thue_nt, g.$a.thue_tg], [g.$a.t_nk_nt, g.$a.t_nk, g.$a.t_ttdb_nt, g.$a.t_ttdb, g.$a.t_thue_nt, g.$a.t_thue], [g.$a.t_tt_nt, g.$a.t_tt], 'nk_nt');
      }
      break;
    case 'ExciseTaxCode':
      if (g._getItemValue(o.row, g._getColumnOrder('thue_suat_ttdb')) != result[0].value) {
        g.setItemGridBehavior(o, [['thue_suat_ttdb', result[0].Value, '', false]]);
        g.validExpression(o, [g.$a.ttdb_nt, g.$a.ttdb_tg, g.$a.thue_nt, g.$a.thue_tg], [g.$a.t_ttdb_nt, g.$a.t_ttdb, g.$a.t_thue_nt, g.$a.t_thue], [g.$a.t_tt_nt, g.$a.t_tt], 'ttdb_nt');
      }
      break;
    case 'GetTaxRate':
      if (g._getItemValue(o.row, g._getColumnOrder('thue_suat')) != result[0].value) {
        g.setItemGridBehavior(o, [['thue_suat', result[0].Value, '', false]]);
        g.validExpression(o, [g.$a.thue_nt, g.$a.thue_tg], [g.$a.t_thue_nt, g.$a.t_thue], [g.$a.t_tt_nt, g.$a.t_tt], 'thue_nt');
      }
      break;
    default:
      break;
  }
}
